@namespace Lumeo
@typeparam TItem
@implements IAsyncDisposable
@inject Lumeo.Services.Localization.ILumeoLocalizer L
@inject IComponentInteropService Interop

<div class="@CssClass"
     style="display:grid;grid-template-columns:1fr auto 1fr;gap:0.75rem;align-items:stretch;"
     @attributes="AdditionalAttributes">

    @* Source panel *@
    <div class="flex flex-col border border-border/40 rounded-lg overflow-hidden bg-card" style="min-width:0;">
        <div class="px-3 py-2 border-b border-border/40 bg-muted/30 flex items-center justify-between">
            <span class="text-sm font-medium">@(SourceTitle ?? L["PickList.SourceHeader"])</span>
            <span class="text-xs text-muted-foreground">@_sourceSelected.Count / @_sourceItems.Count</span>
        </div>
        @if (ShowSearch)
        {
            <div class="px-2 py-1.5 border-b border-border/40">
                <input type="text" placeholder="@L["Common.Search"]"
                       class="flex h-7 w-full rounded-md border border-input bg-transparent px-2 py-1 text-xs placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring"
                       value="@_sourceSearch"
                       @oninput="OnSourceSearch" />
            </div>
        }
        <div id="@_sourceListId" role="listbox" aria-label="@(SourceTitle ?? L["PickList.SourceHeader"])" aria-multiselectable="true" class="overflow-y-auto p-1" style="height:@Height;">
            @if (FilteredSourceItems.Count > 0)
            {
                @for (var i = 0; i < FilteredSourceItems.Count; i++)
                {
                    var index = i;
                    var item = FilteredSourceItems[index];
                    var selected = _sourceSelected.Contains(item);
                    <button @key="(object?)item" type="button" id="@ItemId(_sourceListId, index)"
                            role="option" aria-selected="@(selected ? "true" : "false")"
                            tabindex="@(index == SourceFocusIndex ? "0" : "-1")"
                            class="@RowClass(selected)"
                            @onclick="() => ToggleSource(item)"
                            @onfocus="() => SetSourceFocus(index, item)"
                            @onkeydown="e => HandleSourceKeyDown(e, index)">
                        @if (ItemTemplate != null)
                        {
                            @ItemTemplate(item)
                        }
                        else
                        {
                            <span class="truncate">@(item?.ToString() ?? "")</span>
                        }
                    </button>
                }
            }
            else
            {
                <div class="text-center text-xs text-muted-foreground py-6">@L["PickList.NoItems"]</div>
            }
        </div>
    </div>

    @* Middle buttons *@
    <div class="flex flex-col items-center justify-center gap-1.5">
        <Tooltip>
            <TooltipTrigger AsChild>
                <ChildContentSlot Context="slot">
                    <button type="button" class="@ButtonClass" @onclick="MoveAllToTarget" disabled="@(FilteredSourceItems.Count == 0)" aria-label="@L["PickList.MoveAll"]" @attributes="slot.Attributes">
                        <SvgGlyph Svg="@(LumeoIcons.ChevronsRight)" class="h-4 w-4" />
                    </button>
                </ChildContentSlot>
            </TooltipTrigger>
            <TooltipContent>@L["PickList.MoveAll"]</TooltipContent>
        </Tooltip>
        <Tooltip>
            <TooltipTrigger AsChild>
                <ChildContentSlot Context="slot">
                    <button type="button" class="@ButtonClass" @onclick="MoveSelectedToTarget" disabled="@(_sourceSelected.Count == 0)" aria-label="@L["PickList.MoveSelected"]" @attributes="slot.Attributes">
                        <SvgGlyph Svg="@(LumeoIcons.ChevronRight)" class="h-4 w-4" />
                    </button>
                </ChildContentSlot>
            </TooltipTrigger>
            <TooltipContent>@L["PickList.MoveSelected"]</TooltipContent>
        </Tooltip>
        <Tooltip>
            <TooltipTrigger AsChild>
                <ChildContentSlot Context="slot">
                    <button type="button" class="@ButtonClass" @onclick="MoveSelectedToSource" disabled="@(_targetSelected.Count == 0)" aria-label="@L["PickList.MoveBackSelected"]" @attributes="slot.Attributes">
                        <SvgGlyph Svg="@(LumeoIcons.ChevronLeft)" class="h-4 w-4" />
                    </button>
                </ChildContentSlot>
            </TooltipTrigger>
            <TooltipContent>@L["PickList.MoveBackSelected"]</TooltipContent>
        </Tooltip>
        <Tooltip>
            <TooltipTrigger AsChild>
                <ChildContentSlot Context="slot">
                    <button type="button" class="@ButtonClass" @onclick="MoveAllToSource" disabled="@(FilteredTargetItems.Count == 0)" aria-label="@L["PickList.MoveBackAll"]" @attributes="slot.Attributes">
                        <SvgGlyph Svg="@(LumeoIcons.ChevronsLeft)" class="h-4 w-4" />
                    </button>
                </ChildContentSlot>
            </TooltipTrigger>
            <TooltipContent>@L["PickList.MoveBackAll"]</TooltipContent>
        </Tooltip>
    </div>

    @* Target panel *@
    <div class="flex flex-col border border-border/40 rounded-lg overflow-hidden bg-card" style="min-width:0;">
        <div class="px-3 py-2 border-b border-border/40 bg-muted/30 flex items-center justify-between gap-2">
            <span class="text-sm font-medium truncate">@(TargetTitle ?? L["PickList.TargetHeader"])</span>
            <div class="flex items-center gap-1.5 shrink-0">
                @if (Reorderable)
                {
                    <Tooltip>
                        <TooltipTrigger AsChild>
                            <ChildContentSlot Context="slot">
                                <button type="button" class="@ReorderButtonClass" @onclick="MoveSelectedUp" disabled="@(!CanReorder)" aria-label="@L["PickList.MoveUp"]" @attributes="slot.Attributes">
                                    <SvgGlyph Svg="@(LumeoIcons.ChevronUp)" class="h-3.5 w-3.5" />
                                </button>
                            </ChildContentSlot>
                        </TooltipTrigger>
                        <TooltipContent>@L["PickList.MoveUp"]</TooltipContent>
                    </Tooltip>
                    <Tooltip>
                        <TooltipTrigger AsChild>
                            <ChildContentSlot Context="slot">
                                <button type="button" class="@ReorderButtonClass" @onclick="MoveSelectedDown" disabled="@(!CanReorder)" aria-label="@L["PickList.MoveDown"]" @attributes="slot.Attributes">
                                    <SvgGlyph Svg="@(LumeoIcons.ChevronDown)" class="h-3.5 w-3.5" />
                                </button>
                            </ChildContentSlot>
                        </TooltipTrigger>
                        <TooltipContent>@L["PickList.MoveDown"]</TooltipContent>
                    </Tooltip>
                }
                <span class="text-xs text-muted-foreground">@_targetSelected.Count / @_targetItems.Count</span>
            </div>
        </div>
        @if (ShowSearch)
        {
            <div class="px-2 py-1.5 border-b border-border/40">
                <input type="text" placeholder="@L["Common.Search"]"
                       class="flex h-7 w-full rounded-md border border-input bg-transparent px-2 py-1 text-xs placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring"
                       value="@_targetSearch"
                       @oninput="OnTargetSearch" />
            </div>
        }
        <div id="@_targetListId" role="listbox" aria-label="@(TargetTitle ?? L["PickList.TargetHeader"])" aria-multiselectable="true" class="overflow-y-auto p-1" style="height:@Height;">
            @if (FilteredTargetItems.Count > 0)
            {
                @for (var i = 0; i < FilteredTargetItems.Count; i++)
                {
                    var index = i;
                    var item = FilteredTargetItems[index];
                    var selected = _targetSelected.Contains(item);
                    <button @key="(object?)item" type="button" id="@ItemId(_targetListId, index)"
                            role="option" aria-selected="@(selected ? "true" : "false")"
                            tabindex="@(index == TargetFocusIndex ? "0" : "-1")"
                            class="@RowClass(selected)"
                            @onclick="() => ToggleTarget(item)"
                            @onfocus="() => SetTargetFocus(index, item)"
                            @onkeydown="e => HandleTargetKeyDown(e, index)">
                        @if (ItemTemplate != null)
                        {
                            @ItemTemplate(item)
                        }
                        else
                        {
                            <span class="truncate">@(item?.ToString() ?? "")</span>
                        }
                    </button>
                }
            }
            else
            {
                <div class="text-center text-xs text-muted-foreground py-6">@L["PickList.NoItems"]</div>
            }
        </div>
    </div>
</div>

@code {
    /// <summary>The full candidate set. Items present in <see cref="SelectedItems"/> render in the target panel; the rest render in the source panel.</summary>
    [Parameter] public IEnumerable<TItem> Items { get; set; } = [];
    /// <summary>The items currently in the target panel, in display order. Bind via <c>@bind-SelectedItems</c> to receive reorders and moves.</summary>
    [Parameter] public IEnumerable<TItem> SelectedItems { get; set; } = [];
    /// <summary>Raised whenever the target panel's contents or order changes — moves between panels, and (when <see cref="Reorderable"/>) in-panel reordering.</summary>
    [Parameter] public EventCallback<IEnumerable<TItem>> SelectedItemsChanged { get; set; }
    /// <summary>Optional custom render fragment for a row's content in both panels. Defaults to <c>item.ToString()</c>.</summary>
    [Parameter] public RenderFragment<TItem>? ItemTemplate { get; set; }
    /// <summary>Source panel header. Defaults to the localized "Available".</summary>
    [Parameter] public string? SourceTitle { get; set; }
    /// <summary>Target panel header. Defaults to the localized "Selected".</summary>
    [Parameter] public string? TargetTitle { get; set; }
    /// <summary>When <c>true</c> (default), each panel shows a search box that filters its rows by <c>ToString()</c> substring match.</summary>
    [Parameter] public bool ShowSearch { get; set; } = true;
    /// <summary>When true (default), the target list can be reordered: header
    /// up/down buttons and Alt+ArrowUp/ArrowDown on a focused target item move
    /// the selected items within the target order, emitting
    /// <see cref="SelectedItemsChanged"/>. Reorder is gated while a target search
    /// is active (a filtered view has no stable order to shuffle).</summary>
    [Parameter] public bool Reorderable { get; set; } = true;
    /// <summary>CSS height applied to both panels' scrollable list area (default <c>"320px"</c>).</summary>
    [Parameter] public string Height { get; set; } = "320px";
    /// <summary>Additional CSS classes merged onto the root grid container.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Unmatched attributes splatted onto the root grid container.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private List<TItem> _sourceItems = new();
    private List<TItem> _targetItems = new();
    // CONTROLLED discriminator: the last SelectedItems order/set we pushed UP via
    // SelectedItemsChanged (also re-synced whenever we adopt an authoritative
    // SelectedItems). A controlled parent re-render that echoes back this exact
    // order is safe to ignore (keep in-flight _targetItems); any other order/set
    // is an authoritative assertion (veto / external reorder / reset) and must win.
    private List<TItem>? _lastPushedSelectedItems;
    // The last SelectedItems SET (content, not order) we last SAW as an incoming parameter, regardless
    // of source. Distinguishes a TRUE veto/reset (the parent supplies a genuinely different set) from
    // an observer-only consumer that binds SelectedItemsChanged purely to react to it without echoing
    // SelectedItems back — see the #38 carve-out below, now also honoured in CONTROLLED mode.
    private List<TItem>? _lastSelectedItemsParam;
    private readonly HashSet<TItem> _sourceSelected = new();
    private readonly HashSet<TItem> _targetSelected = new();
    private string _sourceSearch = "";
    private string _targetSearch = "";

    // Roving-tabindex focus targets (one tabbable option per list).
    private int _sourceFocusIndex;
    private int _targetFocusIndex;
    // #71 — anchor the roving focus to the focused *item* (stable identity), not a
    // bare position. After items move between panels or reorder, the positional
    // index points at a different item; remembering the item lets us re-resolve
    // the index to the same item (falling back to a clamp only when it's gone).
    private TItem? _sourceFocusItem;
    private TItem? _targetFocusItem;
    private readonly string _sourceListId = LumeoIds.New("picklist-src");
    private readonly string _targetListId = LumeoIds.New("picklist-tgt");

    private static string ItemId(string listId, int index) => $"{listId}-{index}";

    // Resolve the roving index from the remembered focused item so the tabbable
    // option stays anchored to the user's place after items move/reorder. Falls
    // back to a clamp of the last positional index only when the item is gone,
    // so a tabbable option always exists even after items leave the panel.
    private int SourceFocusIndex => ResolveFocusIndex(FilteredSourceItems, _sourceFocusItem, _sourceFocusIndex);
    private int TargetFocusIndex => ResolveFocusIndex(FilteredTargetItems, _targetFocusItem, _targetFocusIndex);

    private static int ResolveFocusIndex(List<TItem> filtered, TItem? focusItem, int lastIndex)
    {
        if (filtered.Count == 0) return 0;
        if (focusItem is not null)
        {
            var found = filtered.IndexOf(focusItem);
            if (found >= 0) return found;
        }
        return Math.Clamp(lastIndex, 0, filtered.Count - 1);
    }

    private string CssClass => Cx.Merge("w-full", Class);

    private const string ButtonClass = "inline-flex items-center justify-center h-8 w-8 rounded-md border border-border/60 bg-background hover:bg-accent hover:text-accent-foreground transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2 disabled:opacity-40 disabled:cursor-not-allowed";
    private const string ReorderButtonClass = "inline-flex items-center justify-center h-6 w-6 rounded-md border border-border/60 bg-background hover:bg-accent hover:text-accent-foreground transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 disabled:opacity-40 disabled:cursor-not-allowed";

    private string RowClass(bool selected) =>
        selected
            ? "w-full text-start flex items-center gap-2 px-2 py-1.5 rounded-md text-sm bg-accent text-accent-foreground transition-colors"
            : "w-full text-start flex items-center gap-2 px-2 py-1.5 rounded-md text-sm hover:bg-accent/50 transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1";

    protected override void OnParametersSet()
    {
        var all = (Items ?? []).ToList();
        var sel = (SelectedItems ?? []).ToList();
        var selSet = new HashSet<TItem>(sel);

        if (SelectedItemsChanged.HasDelegate)
        {
            // CONTROLLED: the parent owns SelectedItems.
            // Echo of our own push (sel sequence-equals what we last pushed via
            // SelectedItemsChanged) → keep the in-flight _targetItems as-is.
            //
            // ALSO a no-op: the incoming SET (order ignored) is unchanged from what we last saw as a
            // PARAMETER before this interaction (_lastSelectedItemsParam). This is the #38 contract —
            // an observer that binds SelectedItemsChanged purely to react to moves, without echoing
            // SelectedItems back, must not have its local reorder snapped back by its own re-render;
            // a same-set re-render is indistinguishable from "hasn't propagated yet", so it stays local.
            //
            // Anything else — a set that differs from BOTH our own push AND the pre-interaction
            // snapshot — is an authoritative, distinguishable assertion (veto / external reorder /
            // reset) and must win.
            var isEcho = _lastPushedSelectedItems is not null && sel.SequenceEqual(_lastPushedSelectedItems);
            // Gate the "unchanged from before" check behind an ACTUAL in-flight push: only treat
            // incoming-equals-pre-interaction-set as ambiguous when _lastPushedSelectedItems genuinely
            // differs from _lastSelectedItemsParam (a local interaction pushed something new since the
            // baseline was last observed). Without this gate, a SET-equality check alone also (wrongly)
            // swallows a pure EXTERNAL reorder that happens with NO prior local interaction — e.g. a
            // server-driven sort to the same set in a different order, fired before the user ever
            // touched the list. There, _lastPushedSelectedItems still equals _lastSelectedItemsParam
            // (nothing pushed it apart from the baseline yet), so the gate is false and the external
            // reorder is adopted normally, exactly like the OUTER isEcho/distinct-value cases.
            var hasInFlightPush = _lastPushedSelectedItems is not null && _lastSelectedItemsParam is not null
                && !_lastPushedSelectedItems.SequenceEqual(_lastSelectedItemsParam);
            var isUnchangedSetFromBeforeInteraction = hasInFlightPush
                && selSet.SetEquals(_lastSelectedItemsParam!);
            if (!isEcho && !isUnchangedSetFromBeforeInteraction)
            {
                _targetItems = sel;
                _lastPushedSelectedItems = sel;
            }
        }
        else if (sel.Count == _targetItems.Count && selSet.SetEquals(_targetItems))
        {
            // #38 — UNCONTROLLED (nobody observes SelectedItemsChanged): within-target
            // reorder is owned by the component until the *set* of selected items
            // actually changes. If the incoming SelectedItems is the same set we
            // already hold (the parent simply didn't echo the emitted order, or
            // re-rendered for an unrelated reason), keep the user's current ordering
            // instead of snapping back to the parameter's order.
            // Same set, possibly reordered: preserve _targetItems as-is.
        }
        else
        {
            _targetItems = sel;
        }
        _lastSelectedItemsParam = sel;
        _sourceItems = all.Where(i => !_targetItems.Contains(i)).ToList();

        // Clean out selections that are no longer in their side. Guard against
        // a transient-empty incoming Items during async refresh (#37): a wholly
        // empty incoming Items snapshot (a loading flicker) must not wipe the
        // user's in-progress source checkbox selection — only prune once there is
        // a settled (non-empty) data set to reconcile against.
        if (all.Count > 0)
        {
            _sourceSelected.RemoveWhere(i => !_sourceItems.Contains(i));
        }
        _targetSelected.RemoveWhere(i => !_targetItems.Contains(i));
    }

    // Memoised filter lists. Re-run only when the source/target item list
    // reference OR the corresponding search string changes — instead of
    // every render. The dual-list layout reads both Filtered* properties
    // per render, plus they're touched again inside CountClass / Move*
    // handlers, so the previous getter-based filter was running 4-8×
    // per parent re-render.
    private List<TItem> _sourceFilterCache = [];
    private List<TItem> _sourceFilterCacheBase = [];
    private string _sourceFilterCacheTerm = "";
    private List<TItem> _targetFilterCache = [];
    private List<TItem> _targetFilterCacheBase = [];
    private string _targetFilterCacheTerm = "";

    private List<TItem> FilteredSourceItems
    {
        get
        {
            if (!ReferenceEquals(_sourceFilterCacheBase, _sourceItems)
                || _sourceFilterCacheTerm != _sourceSearch)
            {
                _sourceFilterCacheBase = _sourceItems;
                _sourceFilterCacheTerm = _sourceSearch;
                _sourceFilterCache = string.IsNullOrWhiteSpace(_sourceSearch)
                    ? _sourceItems
                    : _sourceItems.Where(i => (i?.ToString() ?? "").Contains(_sourceSearch, StringComparison.OrdinalIgnoreCase)).ToList();
            }
            return _sourceFilterCache;
        }
    }

    private List<TItem> FilteredTargetItems
    {
        get
        {
            if (!ReferenceEquals(_targetFilterCacheBase, _targetItems)
                || _targetFilterCacheTerm != _targetSearch)
            {
                _targetFilterCacheBase = _targetItems;
                _targetFilterCacheTerm = _targetSearch;
                _targetFilterCache = string.IsNullOrWhiteSpace(_targetSearch)
                    ? _targetItems
                    : _targetItems.Where(i => (i?.ToString() ?? "").Contains(_targetSearch, StringComparison.OrdinalIgnoreCase)).ToList();
            }
            return _targetFilterCache;
        }
    }

    private void OnSourceSearch(ChangeEventArgs e) => _sourceSearch = e.Value?.ToString() ?? "";
    private void OnTargetSearch(ChangeEventArgs e) => _targetSearch = e.Value?.ToString() ?? "";

    private void ToggleSource(TItem item)
    {
        if (!_sourceSelected.Add(item)) _sourceSelected.Remove(item);
    }

    private void ToggleTarget(TItem item)
    {
        if (!_targetSelected.Add(item)) _targetSelected.Remove(item);
    }

    // ---- Keyboard operation (WAI-ARIA listbox) ----
    // Arrow keys move the roving focus within a list; Home/End jump to the
    // ends; Space/Enter toggle selection. In the target list Alt+ArrowUp /
    // Alt+ArrowDown reorder the selected item(s) one slot (#203).
    private async Task HandleSourceKeyDown(KeyboardEventArgs e, int index)
    {
        switch (e.Key)
        {
            case "ArrowDown": await MoveSourceFocus(index + 1); break;
            case "ArrowUp": await MoveSourceFocus(index - 1); break;
            case "Home": await MoveSourceFocus(0); break;
            case "End": await MoveSourceFocus(FilteredSourceItems.Count - 1); break;
            // Enter/Space intentionally not handled: each row is a native <button>
            // whose @onclick already toggles it — handling the key here too would
            // double-toggle (select then immediately deselect).
        }
    }

    private async Task HandleTargetKeyDown(KeyboardEventArgs e, int index)
    {
        // Alt + Up/Down reorders within the target list rather than moving focus.
        if (e.AltKey && (e.Key == "ArrowUp" || e.Key == "ArrowDown"))
        {
            await ReorderTarget(e.Key == "ArrowUp" ? -1 : 1);
            return;
        }

        switch (e.Key)
        {
            case "ArrowDown": await MoveTargetFocus(index + 1); break;
            case "ArrowUp": await MoveTargetFocus(index - 1); break;
            case "Home": await MoveTargetFocus(0); break;
            case "End": await MoveTargetFocus(FilteredTargetItems.Count - 1); break;
            // Enter/Space intentionally not handled: native <button> @onclick already toggles.
        }
    }

    // Record the roving focus by both position AND item identity (#71) so the
    // tabbable option stays anchored to the same item if the lists later move
    // or reorder.
    private void SetSourceFocus(int index, TItem item)
    {
        _sourceFocusIndex = index;
        _sourceFocusItem = item;
    }

    private void SetTargetFocus(int index, TItem item)
    {
        _targetFocusIndex = index;
        _targetFocusItem = item;
    }

    private async Task MoveSourceFocus(int target)
    {
        var list = FilteredSourceItems;
        if (list.Count == 0) return;
        var idx = Math.Clamp(target, 0, list.Count - 1);
        SetSourceFocus(idx, list[idx]);
        StateHasChanged();
        try { await Interop.FocusElement(ItemId(_sourceListId, idx)); }
        catch (JSDisconnectedException) { }
    }

    private async Task MoveTargetFocus(int target)
    {
        var list = FilteredTargetItems;
        if (list.Count == 0) return;
        var idx = Math.Clamp(target, 0, list.Count - 1);
        SetTargetFocus(idx, list[idx]);
        StateHasChanged();
        try { await Interop.FocusElement(ItemId(_targetListId, idx)); }
        catch (JSDisconnectedException) { }
    }

    /// <summary>Whether the target list can currently be reordered: enabled, no
    /// active target search (a filtered view has no stable global order), and at
    /// least one item selected.</summary>
    private bool CanReorder => Reorderable && string.IsNullOrWhiteSpace(_targetSearch) && _targetSelected.Count > 0;

    private Task MoveSelectedUp() => ReorderTarget(-1);
    private Task MoveSelectedDown() => ReorderTarget(1);

    /// <summary>Shifts every selected target item one slot in <paramref name="direction"/>
    /// (-1 up, +1 down) within the target order, preserving relative order of the
    /// moved block and clamping at the ends. Iterates from the leading edge so a
    /// multi-item selection slides as a contiguous-ish block without items
    /// hopping over each other.</summary>
    private async Task ReorderTarget(int direction)
    {
        if (!CanReorder) return;

        var list = _targetItems;
        // Process in the order that lets each move "see" already-moved neighbours:
        // moving up walks top→bottom, moving down walks bottom→top.
        var indices = Enumerable.Range(0, list.Count)
            .Where(i => _targetSelected.Contains(list[i]));
        if (direction > 0) indices = indices.Reverse();

        var moved = false;
        foreach (var i in indices.ToList())
        {
            var swap = i + direction;
            if (swap < 0 || swap >= list.Count) continue;
            // Don't swap past another selected item that hasn't been pulled along.
            if (_targetSelected.Contains(list[swap])) continue;
            (list[i], list[swap]) = (list[swap], list[i]);
            moved = true;
        }

        if (!moved) return;
        // Assign a fresh list reference so FilteredTargetItems recomputes against
        // the reordered order (the cache keys on ReferenceEquals of the list).
        _targetItems = new List<TItem>(list);
        // Record _lastPushedSelectedItems BEFORE invoking SelectedItemsChanged: a
        // controlled parent may re-render synchronously inside InvokeAsync, so
        // OnParametersSet must already see this order as "the order we just
        // pushed" to distinguish an accepted echo (keep in-flight state) from a
        // veto (parent kept its old order → roll back).
        _lastPushedSelectedItems = _targetItems.ToList();
        await SelectedItemsChanged.InvokeAsync(_targetItems.ToList());
    }

    private Task MoveSelectedToTarget() => MoveToTarget(_sourceSelected.ToList());
    // #39 — "Move all" operates on the *visible* (filtered) items so an active
    // search never silently moves rows the user can't see. With no search the
    // filtered list is the full list, so the unfiltered behaviour is preserved.
    private Task MoveAllToTarget() => MoveToTarget(FilteredSourceItems.ToList());
    private Task MoveSelectedToSource() => MoveToSource(_targetSelected.ToList());
    private Task MoveAllToSource() => MoveToSource(FilteredTargetItems.ToList());

    private async Task MoveToTarget(List<TItem> toMove)
    {
        if (toMove.Count == 0) return;
        // Build fresh lists rather than mutating in place. The filter caches
        // (FilteredSourceItems / FilteredTargetItems) key on
        // ReferenceEquals against the source / target lists; in-place
        // Remove/Add would keep the same reference and let the cache hit
        // stale after every move — items disappearing from the wrong pane
        // or failing to appear in the other until the user retypes the
        // search (Codex review on #100).
        var moveSet = new HashSet<TItem>(toMove);
        _sourceItems = _sourceItems.Where(i => !moveSet.Contains(i)).ToList();
        _targetItems = _targetItems.Concat(toMove.Where(i => !_targetItems.Contains(i))).ToList();
        _sourceSelected.Clear();
        // Record BEFORE invoking — see ReorderTarget for why.
        _lastPushedSelectedItems = _targetItems.ToList();
        await SelectedItemsChanged.InvokeAsync(_targetItems.ToList());
    }

    private async Task MoveToSource(List<TItem> toMove)
    {
        if (toMove.Count == 0) return;
        var moveSet = new HashSet<TItem>(toMove);
        _targetItems = _targetItems.Where(i => !moveSet.Contains(i)).ToList();
        _sourceItems = _sourceItems.Concat(toMove.Where(i => !_sourceItems.Contains(i))).ToList();
        _targetSelected.Clear();
        // Record BEFORE invoking — see ReorderTarget for why.
        _lastPushedSelectedItems = _targetItems.ToList();
        await SelectedItemsChanged.InvokeAsync(_targetItems.ToList());
    }

    // Suppress page scroll for the list-navigation keys so the first keypress
    // moves the roving focus without also scrolling the page (same pattern as
    // Calendar's day grid). Registered once against each list container.
    private bool _navKeysRegistered;
    private static readonly PreventDefaultKeyRule[] ListNavKeys =
    [
        new("ArrowUp"), new("ArrowDown"), new("Home"), new("End"),
    ];

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender || _navKeysRegistered) return;
        _navKeysRegistered = true;
        try
        {
            await Interop.RegisterPreventDefaultKeys(_sourceListId, ListNavKeys);
            await Interop.RegisterPreventDefaultKeys(_targetListId, ListNavKeys);
        }
        catch (JSDisconnectedException) { _navKeysRegistered = false; }
        catch (InvalidOperationException) { _navKeysRegistered = false; } // prerender
    }

    public async ValueTask DisposeAsync()
    {
        if (!_navKeysRegistered) return;
        try
        {
            await Interop.UnregisterPreventDefaultKeys(_sourceListId);
            await Interop.UnregisterPreventDefaultKeys(_targetListId);
        }
        catch (JSDisconnectedException) { }
    }
}
